func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	for jj := 0; jj < len(oris); jj++ {
		bestIdx := -1
		bestCostIncrease := INF_COST
		bestBackupAssign := Assign{}
		orderId := total_ship + jj
		ori := oris[jj]
		des := dess[jj]

		for idx := 0; idx <= dispatch.AssignsLen; idx++ {
			if idx == MAXASSIGNS {
				continue
			}
			assignCopy := dispatch.Assigns[idx]
			oldCost := assignCopy.Cost
			addOk := assignCopy.AddShip(orderId, ori, des)
			if !addOk {
				continue
			}
			assignCopy.GenRoute()
			newCost := assignCopy.Cost
			if newCost < 0 {
				assignCopy.RemoveShip(orderId)
				assignCopy.GenRoute()
				continue
			}
			costInc := newCost - oldCost
			if costInc < bestCostIncrease {
				bestCostIncrease = costInc
				bestIdx = idx
				bestBackupAssign = dispatch.Assigns[idx]
				bestBackupAssign.AddShip(orderId, ori, des)
