Greedy insertion with regret-based scoring using time window slack and distance savings, falling back to earliest feasible empty assign if no existing route accepts the order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type insertOption struct {
		assignIdx int
		costDelta float64
		regretK2  float64
		feasible  bool
		insertPos int
	}
	nOrders := len(oris)
	if nOrders != len(dess) || nOrders == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for jj := 0; jj < nOrders; jj++ {
		best := insertOption{-1, 0, 0, false, -1}
		secondBest := insertOption{-1, 0, 0, false, -1}
		orderID := total_ship + jj
		ori := oris[jj]
		des := dess[jj]
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			tmpAssign := dispatch.Assigns[ai]
			snapshotCost := tmpAssign.Cost
			if tmpAssign.AddShip(orderID, ori, des) {
				tmpAssign.GenRoute()
				newCost := tmpAssign.Cost
				if newCost >= 0 {
					delta := newCost - snapshotCost
					io := insertOption{assignIdx: ai, costDelta: delta, feasible: true}
					if !best.feasible || io.costDelta < best.costDelta {
						secondBest = best
						best = io
					} else if !secondBest.feasible || io.costDelta < secondBest.costDelta {
						secondBest = io
					}
				}
				tmpAssign.RemoveShip(orderID)
				tmpAssign.GenRoute()
			}
		}
		if best.feasible {
			actualAssign := &dispatch.Assigns[best.assignIdx]
			snapC := actualAssign.Cost
			ok := actualAssign.AddShip(orderID, ori, des)
			if ok {
				actualAssign.GenRoute()
				if actualAssign.Cost < 0 {
					actualAssign.RemoveShip(orderID)
					actualAssign.GenRoute()
					actualAssign.Cost = snapC
					best.feasible = false
				}
			} else {
				best.feasible = false
			}
		}
		if !best.feasible {
			for ai := 0; ai < MAXASSIGNS; ai++ {
				tmpAssign := dispatch.Assigns[ai]
				snapshotCost := tmpAssign.Cost
				if tmpAssign.StationsLen == 0 && ai >= dispatch.AssignsLen {
					dispatch.AssignsLen = ai + 1
				}
				if tmpAssign.StationsLen == 0 || ai < dispatch.AssignsLen {
					ok := tmpAssign.AddShip(orderID, ori, des)
					if ok {
						tmpAssign.GenRoute()
						if tmpAssign.Cost >= 0 {
							best = insertOption{assignIdx: ai, costDelta: tmpAssign.Cost - snapshotCost, feasible: true}
							break
						} else {
							tmpAssign.RemoveShip(orderID)
							tmpAssign.GenRoute()
							tmpAssign.Cost = snapshotCost
						}
					}
				}
			}
		}
		if best.feasible {
			targetAssign := &dispatch.Assigns[best.assignIdx]
			if targetAssign.StationsLen == 0 && best.assignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = best.assignIdx + 1
			}
			snapC := targetAssign.Cost
			ok := targetAssign.AddShip(orderID, ori, des)
			if ok {
				targetAssign.GenRoute()
				if targetAssign.Cost < 0 {
					targetAssign.RemoveShip(orderID)
					targetAssign.GenRoute()
					targetAssign.Cost = snapC
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

