population.algorithm:
Iteratively attempt to insert each ship into all existing routes sorted by current accumulated distance, evaluate insertion feasibility via AddShip/GenRoute, keep the best feasible insertion minimizing added cost, if none succeed then create a new route.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		addedCost float64
		valid     bool
	}
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		bestCand := cand{idx: -1, addedCost: 1e18, valid: false}
		orderID := total_ship + shipIdx
		ori, des := oris[shipIdx], dess[shipIdx]

		for rIdx := 0; rIdx < MAXASSIGNS; rIdx++ {
			prevCost := dispatch.Assigns[rIdx].Cost
			if prevCost < 0 {
				prevCost = 0
			}
			ok := dispatch.Assigns[rIdx].AddShip(orderID, ori, des)
			if ok {
				dispatch.Assigns[rIdx].GenRoute()
				newCost := dispatch.Assigns[rIdx].Cost
				if newCost >= 0 {
					addedCost := newCost - prevCost
					if addedCost < bestCand.addedCost {
						bestCand.idx = rIdx
						bestCand.addedCost = addedCost
						bestCand.valid = true
					}
				}
				dispatch.Assigns[rIdx].RemoveShip(orderID)
				dispatch.Assigns[rIdx].GenRoute()
			}
		}

		if bestCand.valid {
			dispatch.Assigns[bestCand.idx].AddShip(orderID, ori, des)
			dispatch.Assigns[bestCand.idx].GenRoute()
			if bestCand.idx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestCand.idx + 1
			}
		} else {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(orderID, ori, des)
				dispatch.Assigns[fallbackIdx].GenRoute()
				if dispatch.Assigns[fallbackIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[fallbackIdx].RemoveShip(orderID)
					dispatch.Assigns[fallbackIdx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
