func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type insertOption struct {
		assignIdx int
		deltaCost float64
		insertPos int
		feasible  bool
	}
	nextAssignIdx := dispatch.AssignsLen
	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		bestOption := insertOption{-1, 1e100, -1, false}
		maxCheckAssigns := nextAssignIdx
		if maxCheckAssigns < MAXASSIGNS {
			maxCheckAssigns++
		}
		for ii := 0; ii < maxCheckAssigns; ii++ {
			tempAssign := dispatch.Assigns[ii]
			prevCost := tempAssign.Cost
			id := total_ship + jj
			addOk := tempAssign.AddShip(id, oris[jj], dess[jj])
			if !addOk {
				continue
			}
			tempAssign.GenRoute()
			newCost := tempAssign.Cost
			if newCost >= 0 {
				delta := newCost - prevCost
				if delta < bestOption.deltaCost {
					bestOption.assignIdx = ii
					bestOption.deltaCost = delta
					bestOption.feasible = true
				}
			}
			tempAssign.RemoveShip(id)
			tempAssign.GenRoute()
		}
		if bestOption.feasible {
			finalIdx := bestOption.assignIdx
			id := total_ship + jj
			dispatch.Assigns[finalIdx].AddShip(id, oris[jj], dess[jj])
			dispatch.Assigns[finalIdx].GenRoute()
			if finalIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = finalIdx + 1
			}
		} else {
			if nextAssignIdx < MAXASSIGNS {
				id := total_ship + jj
				dispatch.Assigns[nextAssignIdx].AddShip(id, oris[jj], dess[jj])
				dispatch.Assigns[nextAssignIdx].GenRoute()
				if dispatch.Assigns[nextAssignIdx].Cost >= 0 {
					nextAssignIdx++
