Greedy best-fit insertion evaluating marginal cost increase per candidate assign with fallback to expanding fleet if all existing assigns reject the insertion.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx        int
		marginal   float64
		costBefore float64
	}
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	activeLimit := dispatch.AssignsLen
	for i := 0; i < activeLimit; i++ {
		if dispatch.Assigns[i].StationsLen <= 0 {
			for j := i + 1; j < MAXASSIGNS; j++ {
				if j < dispatch.AssignsLen && dispatch.Assigns[j].StationsLen > 0 {
					dispatch.Assigns[i], dispatch.Assigns[j] = dispatch.Assigns[j], dispatch.Assigns[i]
					break
				}
			}
		}
	}
	newActiveLimit := 0
	for i := 0; i < activeLimit; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			newActiveLimit++
		}
	}
	activeLimit = newActiveLimit
	insertSeq := make([]int, activeLimit+MAXASSIGNS-activeLimit)
	for i := range insertSeq {
		insertSeq[i] = i
	}
	for oidx := 0; oidx < orderCount; oidx++ {
		bestCand := cand{idx: -1, marginal: 1e18}
		checkedAny := false
		for tryIdx := 0; tryIdx < activeLimit; tryIdx++ {
			assignIdx := insertSeq[tryIdx]
			if assignIdx >= MAXASSIGNS {
				continue
			}
			costBefore := dispatch.Assigns[assignIdx].Cost
			ok := dispatch.Assigns[assignIdx].AddShip(total_ship+oidx, oris[oidx], dess[oidx])
			if ok {
				dispatch.Assigns[assignIdx].GenRoute()
				if dispatch.Assigns[assignIdx].Cost >= 0 {
					marginal := dispatch.Assigns[assignIdx].Cost - costBefore
					if marginal < bestCand.marginal {
						bestCand = cand{idx: assignIdx, marginal: marginal, costBefore: costBefore}
					}
					checkedAny = true
				}
				dispatch.Assigns[assignIdx].RemoveShip(total_ship + oidx)
				dispatch.Assigns[assignIdx].GenRoute()
			}
		}
		fallbackIdx := -1
		if !checkedAny || bestCand.idx == -1 {
			startFleet := activeLimit
			if startFleet >= MAXASSIGNS {
				startFleet = dispatch.AssignsLen
			}
			for fi := startFleet; fi < MAXASSIGNS; fi++ {
				origLen := dispatch.Assigns[fi].StationsLen
				ok := dispatch.Assigns[fi].AddShip(total_ship+oidx, oris[oidx], dess[oidx])
				if ok {
					dispatch.Assigns[fi].GenRoute()
					if dispatch.Assigns[fi].Cost >= 0 {
						fallbackIdx = fi
						if fi >= dispatch.AssignsLen {
							dispatch.AssignsLen = fi + 1
						}
						if origLen == 0 && fi >= activeLimit {
							activeLimit = fi + 1
							if activeLimit > dispatch.AssignsLen {
								activeLimit = dispatch.AssignsLen
							}
						}
						break
					} else {
						dispatch.Assigns[fi].RemoveShip(total_ship + oidx)
						dispatch.Assigns[fi].GenRoute()
					}
				}
			}
		} else {
			targetIdx := bestCand.idx
			dispatch.Assigns[targetIdx].AddShip(total_ship+oidx, oris[oidx], dess[oidx])
			dispatch.Assigns[targetIdx].GenRoute()
		}
		if checkedAny && bestCand.idx == -1 && fallbackIdx == -1 {
			for fi := activeLimit; fi < MAXASSIGNS; fi++ {
				origLen := dispatch.Assigns[fi].StationsLen
				ok := dispatch.Assigns[fi].AddShip(total_ship+oidx, oris[oidx], dess[oidx])
				if ok {
					dispatch.Assigns[fi].GenRoute()
					if dispatch.Assigns[fi].Cost >= 0 {
						if fi >= dispatch.AssignsLen {
							dispatch.AssignsLen = fi + 1
						}
						if origLen == 0 && fi >= activeLimit {
							activeLimit = fi + 1
							if activeLimit > dispatch.AssignsLen {
								activeLimit = dispatch.AssignsLen
							}
						}
						break
					} else {
						dispatch.Assigns[fi].RemoveShip(total_ship + oidx)
						dispatch.Assigns[fi].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

