filtered_best_population_item.algorithm:
Modified greedy insertion with cost-aware candidate evaluation and fallback expansion using empty assign slots.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    shipID := total_ship
    for idx := range oris {
        bestAssignIdx := -1
        bestCostDelta := 1e9
        var originalCosts [MAXASSIGNS]float64
        for i := 0; i < dispatch.AssignsLen; i++ {
            originalCosts[i] = dispatch.Assigns[i].Cost
        }
        for i := 0; i < dispatch.AssignsLen; i++ {
            if dispatch.Assigns[i].AddShip(shipID, oris[idx], dess[idx]) {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    delta := dispatch.Assigns[i].Cost - originalCosts[i]
                    if delta < bestCostDelta {
                        bestCostDelta = delta
                        bestAssignIdx = i
                    }
                }
                dispatch.Assigns[i].RemoveShip(shipID)
                dispatch.Assigns[i].GenRoute()
            }
        }
        if bestAssignIdx >= 0 {
            dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[idx], dess[idx])
            dispatch.Assigns[bestAssignIdx].GenRoute()
        } else {
            inserted := false
            for i := 0; i <= dispatch.AssignsLen && i < MAXASSIGNS; i++ {
                if i == dispatch.AssignsLen {
                    if dispatch.AssignsLen < MAXASSIGNS {
                        dispatch.AssignsLen++
                        dispatch.Assigns[i].Cost = 0
                    } else {
                        break
                    }
                }
                if dispatch.Assigns[i].AddShip(shipID, oris[idx], dess[idx]) {
                    dispatch.Assigns[i].GenRoute()
                    if dispatch.Assigns[i].Cost >= 0 {
                        inserted = true
                        if i >= dispatch.AssignsLen {
                            dispatch.AssignsLen = i + 1
                        }
                        break
                    } else {
                        dispatch.Assigns[i].RemoveShip(shipID)
                        dispatch.Assigns[i].GenRoute()
                    }
                }
            }
            if !inserted {
                for i := dispatch.AssignsLen; i < MAXASSIGNS; i++ {
                    if dispatch.Assigns[i].AddShip(shipID, oris[idx], dess[idx]) {
                        dispatch.Assigns[i].GenRoute()
                        dispatch.AssignsLen = i + 1
                        break
                    }
                }
            }
        }
        shipID++
    }
