    if len(oris) != len(dess) || len(oris) == 0 {
        dispatch.RenewnTotalCost()
        return dispatch
    }

    activeIdxs := make([]int, 0, dispatch.AssignsLen)
    for i := 0; i < dispatch.AssignsLen; i++ {
