            activeIdxs = append(activeIdxs, i)
        }
    }
    rand.Shuffle(len(activeIdxs), func(i, j int) {
        activeIdxs[i], activeIdxs[j] = activeIdxs[j], activeIdxs[i]
    })

    allCandidateIdxs := make([]int, 0, MAXASSIGNS)
    for _, idx := range activeIdxs {
        allCandidateIdxs = append(allCandidateIdxs, idx)
    }
    for i := 0; i < MAXASSIGNS; i++ {
        if dispatch.AssignsLen <= i {
            allCandidateIdxs = append(allCandidateIdxs, i)
            break
        }
    }

    for jj := range oris {
        bestIdx := -1
        var bestDelta float64
        bestValid := false

        for _, candIdx := range allCandidateIdxs {
            originalCost := dispatch.Assigns[candIdx].Cost

            added := dispatch.Assigns[candIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
            if added {
                dispatch.Assigns[candIdx].GenRoute()
                newCost := dispatch.Assigns[candIdx].Cost

                if newCost >= 0 {
                    delta := newCost - originalCost
                    if !bestValid || delta < bestDelta {
                        bestDelta = delta
                        bestIdx = candIdx
                        bestValid = true
                    }
                }
            }

            if added {
                dispatch.Assigns[candIdx].RemoveShip(total_ship + jj)
                dispatch.Assigns[candIdx].GenRoute()
            }
        }

        if bestValid {
            dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
            dispatch.Assigns[bestIdx].GenRoute()
            if bestIdx >= dispatch.AssignsLen {
                dispatch.AssignsLen = bestIdx + 1
            }
        } else {
            placed := false
            for tryIdx := 0; tryIdx < MAXASSIGNS; tryIdx++ {
                if tryIdx < dispatch.AssignsLen {
                    if dispatch.Assigns[tryIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
                        dispatch.Assigns[tryIdx].GenRoute()
                        if dispatch.Assigns[tryIdx].Cost >= 0 {
                            placed = true
                            break
                        }
                        dispatch.Assigns[tryIdx].RemoveShip(total_ship + jj)
                        dispatch.Assigns[tryIdx].GenRoute()
                    }
                } else {
                    if dispatch.Assigns[tryIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
                        dispatch.Assigns[tryIdx].GenRoute()
                        if dispatch.Assigns[tryIdx].Cost >= 0 {
                            dispatch.AssignsLen = tryIdx + 1
                            placed = true
                            break
                        }
                        dispatch.Assigns[tryIdx].RemoveShip(total_ship + jj)
                        dispatch.Assigns[tryIdx].GenRoute()
                    }
                    break
                }
            }
            if !placed {
