func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	assignIndices := make([]int, dispatch.AssignsLen)
	for i := range assignIndices {
		assignIndices[i] = i
	}

	for oIdx := 0; oIdx < orderCount; oIdx++ {
		bestAssignIdx := -1
		bestDelta := math.MaxFloat64
		tempDispatch := dispatch

		for _, aIdx := range assignIndices {
			candidate := tempDispatch.Assigns[aIdx]
			addOk := candidate.AddShip(total_ship+oIdx, oris[oIdx], dess[oIdx])
			if !addOk {
				continue
			}
			oldCost := candidate.Cost
			candidate.GenRoute()
			newCost := candidate.Cost
			if newCost >= 0 {
				delta := newCost - oldCost
				if delta < bestDelta {
					bestDelta = delta
					bestAssignIdx = aIdx
				}
			}
			candidate.RemoveShip(total_ship + oIdx)
			candidate.GenRoute()
		}

		inserted := false
		if bestAssignIdx != -1 {
			actualAdd := dispatch.Assigns[bestAssignIdx].AddShip(total_ship+oIdx, oris[oIdx], dess[oIdx])
			if actualAdd {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				inserted = true
			}
		}

		if !inserted {
			fallbackAssigned := false
			for aIdx := 0; aIdx <= dispatch.AssignsLen; aIdx++ {
				if aIdx == MAXASSIGNS {
					break
				}
				actualAdd := dispatch.Assigns[aIdx].AddShip(total_ship+oIdx, oris[oIdx], dess[oIdx])
				if actualAdd {
					dispatch.Assigns[aIdx].GenRoute()
					if aIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = aIdx + 1
					}
					fallbackAssigned = true
					break
				}
			}
			if !fallbackAssigned && dispatch.AssignsLen < MAXASSIGNS {
				aIdx := dispatch.AssignsLen
				actualAdd := dispatch.Assigns[aIdx].AddShip(total_ship+oIdx, oris[oIdx], dess[oIdx])
				if actualAdd {
					dispatch.Assigns[aIdx].GenRoute()
					dispatch.AssignsLen++
					fallbackAssigned = true
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

